s32 uso_skip_to_end(FileState *file)
{
  s32 pad;
  struct { u32 type; u32 size; u32 x; } header;
  s32 new_var;
  do
  {
    new_var = func_800009D8(&header, 12, 1, file);
    pad = header.type;
    if (new_var < 0)
    {
      return D_80013004;
    }
    if (8 != pad)
    {
      ((s32 *) file)[1] += header.size;
    }
  }
  while (header.type != 11);
  return 0;
}
